() => {
    const recyclingText = document.querySelector('iframe').contentDocument.querySelector('p:has(img[alt="Recycling icon"])').innerText;
    const domesticText = document.querySelector('iframe').contentDocument.querySelector('p:has(img[alt="Domestic icon"])').innerText;
    const binText = document.querySelector('iframe').contentDocument.querySelector('p:has(img[alt="Bin icon"])').innerText;

    const extractDate = (text) => text.split(': ')[1];

    return {
        recycling: extractDate(recyclingText),
        domestic: extractDate(domesticText),
        bin: extractDate(binText)
    };
}

